import React, { useState, useEffect, useCallback } from 'react';
import { Flame, Loader2, Sparkles, CheckCircle2, Image as ImageIcon } from 'lucide-react';

const palette = {
  bg: '#1a0e06',
  surface: '#2a1508',
  card: '#1f1009',
  border: '#4a2010',
  ember: '#c0390a',
  flame: '#e85d04',
  gold: '#f48c06',
  yellow: '#faa307',
  cream: '#fdf0dc',
  muted: '#c4845a',
  textDim: '#8a5535',
};

const flameGradient = `linear-gradient(160deg, ${palette.yellow} 0%, ${palette.flame} 40%, ${palette.ember} 80%, #7a1a04 100%)`;

const StepCard = ({ step, onRetry, index }) => {
  return (
    <div
      style={{
        background: `linear-gradient(145deg, #2e1a0a, #1a0c04)`,
        border: `1px solid ${palette.border}`,
        borderRadius: '1.5rem',
        overflow: 'hidden',
        display: 'flex',
        flexDirection: 'column',
        boxShadow: `0 8px 40px rgba(0,0,0,0.5), inset 0 1px 0 rgba(244,140,6,0.08)`,
        transition: 'transform 0.3s ease, box-shadow 0.3s ease',
      }}
      onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-4px)'; e.currentTarget.style.boxShadow = `0 16px 60px rgba(200,60,10,0.25), inset 0 1px 0 rgba(244,140,6,0.12)`; }}
      onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = `0 8px 40px rgba(0,0,0,0.5), inset 0 1px 0 rgba(244,140,6,0.08)`; }}
    >
      {/* Image area */}
      <div style={{ height: '200px', background: '#0e0704', position: 'relative', display: 'flex', alignItems: 'center', justifyContent: 'center', borderBottom: `1px solid ${palette.border}`, overflow: 'hidden' }}>
        {/* ambient glow at bottom */}
        <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: '50%', background: `linear-gradient(to top, rgba(200,57,10,0.15), transparent)`, pointerEvents: 'none', zIndex: 1 }} />

        {step.userImage ? (
          <img src={step.userImage} alt={step.title} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        ) : step.loading ? (
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.75rem' }}>
            <Loader2 style={{ width: 36, height: 36, color: palette.flame, animation: 'spin 1s linear infinite' }} />
            <span style={{ color: palette.muted, fontSize: '0.8rem', fontWeight: 700, letterSpacing: '0.05em' }}>מייצר תמונה...</span>
          </div>
        ) : step.image ? (
          <img src={step.image} alt={step.title} style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        ) : (
          <div style={{ padding: '1.5rem', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
            <ImageIcon style={{ width: 40, height: 40, color: palette.border, marginBottom: '0.5rem' }} />
            <p style={{ color: palette.textDim, fontSize: '0.75rem', marginBottom: '0.75rem' }}>{step.error ? 'שגיאת טעינה' : 'ממתין לתמונה'}</p>
            <button onClick={onRetry} style={{ fontSize: '0.75rem', fontWeight: 700, background: `rgba(200,57,10,0.15)`, color: palette.flame, border: `1px solid rgba(200,57,10,0.3)`, padding: '0.4rem 1rem', borderRadius: '0.75rem', cursor: 'pointer' }}>
              נסה שוב (AI)
            </button>
          </div>
        )}

        {/* Step number badge */}
        <div style={{
          position: 'absolute', top: '0.75rem', right: '0.75rem', zIndex: 10,
          width: '2.5rem', height: '2.5rem', borderRadius: '0.75rem',
          background: flameGradient,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          fontFamily: 'Georgia, serif', fontWeight: 900, fontSize: '1.1rem', color: '#fff',
          boxShadow: `0 4px 16px rgba(200,57,10,0.6)`,
        }}>
          {step.number}
        </div>
      </div>

      {/* Content */}
      <div style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', flexGrow: 1 }}>
        <h3 style={{ fontFamily: 'Georgia, serif', fontSize: '1.25rem', fontWeight: 700, color: palette.cream, marginBottom: '0.6rem', lineHeight: 1.3 }}>{step.title}</h3>
        <p style={{ color: palette.muted, fontSize: '0.95rem', lineHeight: 1.7, marginBottom: '0.75rem', flexGrow: 1 }}>{step.text}</p>

        {step.tip && (
          <div style={{
            background: `linear-gradient(135deg, rgba(244,140,6,0.08), rgba(200,57,10,0.05))`,
            border: `1px solid rgba(244,140,6,0.15)`,
            borderRadius: '0.875rem',
            padding: '0.75rem 1rem',
            display: 'flex', alignItems: 'flex-start', gap: '0.5rem',
          }}>
            <Sparkles style={{ width: 14, height: 14, color: palette.gold, flexShrink: 0, marginTop: 3 }} />
            <p style={{ color: '#c8956a', fontSize: '0.8rem', fontStyle: 'italic', lineHeight: 1.6, margin: 0 }}>{step.tip}</p>
          </div>
        )}
      </div>
    </div>
  );
};

// Decorative fire emoji row
const FireRow = () => (
  <div style={{ display: 'flex', justifyContent: 'center', gap: '0.5rem', marginBottom: '1.5rem', opacity: 0.7 }}>
    {['🔥','✨','🔥','✨','🔥'].map((e, i) => <span key={i} style={{ fontSize: '1.2rem' }}>{e}</span>)}
  </div>
);

const App = () => {
  const [steps, setSteps] = useState([
    { number: 1, title: 'הכנת הבסיס', text: 'לוקחים צלחת לבנה או עיגול קרטון ומצפים אותם בשכבת פלסטלינה חומה. מסביב מסדרים כדורי פלסטלינה אפורים כ"אבנים".', tip: 'טיפ: כדאי למרוח את הפלסטלינה עם האגודל כדי לקבל מראה של אדמה אמיתית.', prompt: 'Kids craft: brown modeling clay spread on a white plate, craft style.', userImage: 'data:image/jpeg;base64,', image: null, loading: false, error: null },
    { number: 2, title: 'מייצבים את המקלות', text: 'לנעוץ 6 מקלות ארטיק רחבים מעץ בתוך אבני הפלסטלינה ליציבות.', tip: 'הקפידו לנעוץ את המקלות עמוק בתוך הפלסטלינה כדי שלא יפלו.', prompt: 'Six wooden sticks standing in a circle on clay base.', userImage: 'data:image/jpeg;base64,', image: null, loading: false, error: null },
    { number: 3, title: 'בונים מבנה קונוס', text: 'משעינים את המקלות אחד על השני לכיוון המרכז, עד שהם נפגשים למעלה ויוצרים צורה של אוהל או קונוס יציב.', tip: 'אם המקלות מחליקים, אפשר לשים גוש קטן של פלסטלינה בנקודת המפגש למעלה.', prompt: 'Popsicle sticks forming a teepee cone shape.', userImage: 'data:image/jpeg;base64,', image: null, loading: false, error: null },
    { number: 4, title: 'מוסיפים אש מפלסטלינה', text: 'למדורה יציבה, מכינים "נחשים" באדום, כתום וצהוב, מסובבים אותם יחד ומצמידים לראש המקלות.', tip: 'אפשר למעוך מעט את קצוות הלהבות כדי שייראו "חדות" כמו אש אמיתית.', prompt: 'Colorful clay flames on top of wooden sticks.', userImage: 'data:image/jpeg;base64,', image: null, loading: false, error: null },
    { number: 5, title: 'לפסל תפוחי אדמה', text: 'מגלגלים כדורי פלסטלינה חומים קטנים ומניחים אותם בתוך בסיס המדורה בין המקלות.', tip: 'אפשר לעשות חורים קטנים עם קיסם על "תפוחי האדמה" למראה טבעי.', prompt: 'Small round brown clay balls at bonfire base.', userImage: 'data:image/jpeg;base64,', image: null, loading: false, error: null },
    { number: 6, title: 'חג שמח ובטוח!', text: 'המדורה שלכם יציבה, יפה וכוללת הכל. שיהיה לכולם חג ל"ג בעומר שמח ובטוח!', tip: 'אל תשכחו לצלם את המדורה המוכנה ולשתף עם חברים!', prompt: 'Finished bonfire craft made of clay and sticks.', userImage: 'data:image/jpeg;base64,', image: null, loading: false, error: null },
  ]);

  const apiKey = '';

  const generateImage = useCallback(async (index) => {
    const step = steps[index];
    if (step.loading || step.userImage) return;
    setSteps(prev => prev.map((s, i) => i === index ? { ...s, loading: true, error: null } : s));
    try {
      const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/imagen-4.0-generate-001:predict?key=${apiKey}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ instances: { prompt: step.prompt }, parameters: { sampleCount: 1 } }),
      });
      const result = await response.json();
      const base64Data = result.predictions?.[0]?.bytesBase64Encoded;
      if (base64Data) {
        setSteps(prev => prev.map((s, i) => i === index ? { ...s, image: `data:image/png;base64,${base64Data}`, loading: false } : s));
      } else { throw new Error(); }
    } catch {
      setSteps(prev => prev.map((s, i) => i === index ? { ...s, loading: false, error: 'שגיאה' } : s));
    }
  }, [steps, apiKey]);

  useEffect(() => { steps.forEach((s, i) => { if (!s.image && !s.userImage) generateImage(i); }); }, []);

  return (
    <div dir="rtl" style={{
      minHeight: '100vh',
      background: palette.bg,
      backgroundImage: `radial-gradient(ellipse at 30% 20%, rgba(180,50,8,0.12) 0%, transparent 50%), radial-gradient(ellipse at 70% 80%, rgba(120,30,5,0.1) 0%, transparent 50%)`,
      fontFamily: 'system-ui, sans-serif',
      padding: '2rem 1rem',
    }}>
      <style>{`
        @keyframes spin { to { transform: rotate(360deg); } }
        @keyframes flicker {
          0%, 100% { opacity: 1; transform: scaleY(1); }
          50% { opacity: 0.85; transform: scaleY(0.97); }
        }
        @keyframes rise {
          0% { opacity: 0; transform: translateY(20px); }
          100% { opacity: 1; transform: translateY(0); }
        }
      `}</style>

      {/* Header */}
      <header style={{ maxWidth: '72rem', margin: '0 auto 4rem', textAlign: 'center' }}>
        <h1 style={{
          fontFamily: 'Georgia, serif',
          fontSize: 'clamp(2.8rem, 8vw, 5.5rem)',
          fontWeight: 900,
          lineHeight: 1.1,
          marginBottom: '1rem',
          letterSpacing: '-0.02em',
        }}>
          <span style={{ color: palette.cream }}>המדורה </span>
          <span style={{ color: palette.flame }}>הגדולה</span>
          <span style={{ color: palette.cream }}> שלי</span>
        </h1>

        {/* Subtitle */}
        <p style={{ color: palette.gold, fontSize: '1.05rem', fontWeight: 600, maxWidth: '32rem', margin: '0 auto 1.2rem', lineHeight: 1.6 }}>
          פעילות יצירה המעשירה שפה: עבודה על אוצר מילים, תיאור פעולות ועידוד שיחה בזמן עשייה משותפת
        </p>

        {/* decorative divider */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '1rem', marginBottom: '1.25rem' }}>
          <div style={{ height: 1, width: '4rem', background: `linear-gradient(to left, ${palette.border}, transparent)` }} />
          <span style={{ color: palette.gold, fontSize: '1rem' }}>🔥</span>
          <div style={{ height: 1, width: '4rem', background: `linear-gradient(to right, ${palette.border}, transparent)` }} />
        </div>

                        {/* Credit */}
        <p style={{ color: palette.muted, fontSize: '0.85rem', fontWeight: 600, marginBottom: '1.75rem' }}>
          לילך כספרי – קלינאית תקשורת
        </p>

        {/* Materials section */}
        <div style={{ maxWidth: '52rem', margin: '0 auto' }}>
          <p style={{ color: palette.cream, fontFamily: 'Georgia, serif', fontSize: '1.1rem', fontWeight: 700, marginBottom: '1rem', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}>
            <span>📦</span> מה צריך להכין?
          </p>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0.85rem' }}>
            {[
              { img: 'data:image/jpeg;base64,', title: 'פלסטלינה חומה/אפורה', sub: 'לבסיס ולאבנים' },
              { img: 'data:image/jpeg;base64,', title: '6 מקלות ארטיק', sub: 'רחבים, מעץ טבעי' },
              { img: 'data:image/jpeg;base64,', title: 'בסיס קשיח', sub: 'צלחת לבנה או קרטון' },
              { img: 'data:image/jpeg;base64,', title: 'פלסטלינה צבעונית', sub: 'אדום, כתום וצהוב לאש' },
            ].map((m, i) => (
              <div key={i} style={{
                display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                background: 'rgba(40,18,5,0.85)',
                border: '1px solid rgba(200,100,20,0.2)',
                borderRadius: '1rem',
                padding: '0.85rem 1rem',
                gap: '0.75rem',
                boxShadow: '0 2px 16px rgba(0,0,0,0.35)',
              }}>
                <div style={{ textAlign: 'right', flexGrow: 1 }}>
                  <div style={{ color: palette.cream, fontWeight: 700, fontSize: '0.95rem', marginBottom: '0.2rem' }}>{m.title}</div>
                  <div style={{ color: palette.muted, fontSize: '0.78rem' }}>{m.sub}</div>
                </div>
                <img src={m.img} alt={m.title} style={{
                  width: '4rem', height: '4rem', borderRadius: '0.75rem',
                  objectFit: 'contain', flexShrink: 0, background: 'rgba(255,255,255,0.06)',
                  border: '1px solid rgba(255,255,255,0.1)',
                }} />
              </div>
            ))}
          </div>
        </div>
      </header>

      {/* Grid */}
      <main style={{ maxWidth: '72rem', margin: '0 auto', display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '1.5rem' }}>
        {steps.map((step, index) => (
          <StepCard key={step.number} step={step} onRetry={() => generateImage(index)} index={index} />
        ))}
      </main>

      {/* Footer */}
      <footer style={{
        maxWidth: '72rem', margin: '4rem auto 0',
        background: `linear-gradient(135deg, #2e1005, #1a0a02)`,
        border: `1px solid ${palette.border}`,
        borderRadius: '2rem',
        padding: '2.5rem',
        display: 'flex', flexWrap: 'wrap', alignItems: 'center', justifyContent: 'space-between', gap: '1.5rem',
        boxShadow: `0 0 80px rgba(180,50,8,0.15), inset 0 1px 0 rgba(244,140,6,0.06)`,
        position: 'relative', overflow: 'hidden',
      }}>
        {/* glow */}
        <div style={{ position: 'absolute', top: '-2rem', right: '-2rem', width: '12rem', height: '12rem', background: `radial-gradient(circle, rgba(200,57,10,0.2), transparent 70%)`, pointerEvents: 'none' }} />

        <div style={{ width: '100%', display: 'flex', justifyContent: 'center', position: 'relative' }}>
          <div style={{
            background: flameGradient,
            borderRadius: '9999px',
            padding: '0.75rem 2.5rem',
            fontWeight: 900,
            fontSize: '1.2rem',
            color: '#fff',
            boxShadow: `0 4px 20px rgba(200,57,10,0.4)`,
            letterSpacing: '0.02em',
          }}>
            ל"ג בעומר שמח! 🔥
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;
